eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   articles: () => (/* binding */ articles),\n/* harmony export */   getArticle: () => (/* binding */ getArticle),\n/* harmony export */   getFeaturedArticle: () => (/* binding */ getFeaturedArticle),\n/* harmony export */   getRecentArticles: () => (/* binding */ getRecentArticles)\n/* harmony export */ });\nconst articles = [\n    {\n        slug: \"credit-personal-2026-ghid-complet\",\n        title: \"Cum Să Obții un Credit Personal \\xeen 2026: Ghid Complet\",\n        excerpt: \"Tot ce trebuie să știi despre creditele personale \\xeen 2026: condiții, dob\\xe2nzi, documente și cum să obții cea mai bună ofertă pentru situația ta.\",\n        date: \"5 Martie 2026\",\n        readTime: \"8 min\",\n        category: \"Ghiduri\",\n        featured: true,\n        sections: [\n            {\n                id: \"ce-este\",\n                heading: \"1. Ce este un credit personal?\",\n                content: [\n                    \"Un credit personal este un \\xeemprumut acordat de o bancă sau instituție financiară fără a necesita o garanție imobiliară. Poate fi utilizat pentru orice scop — renovare, vacanță, achiziții mari sau situații neprevăzute.\",\n                    \"\\xcen 2026, băncile din Rom\\xe2nia oferă credite personale cu sume \\xeentre 1.000 și 150.000 RON și perioade de rambursare de la 6 luni la 10 ani. Dob\\xe2nzile variază \\xeen funcție de bancă, profil financiar și tipul de credit ales.\"\n                ]\n            },\n            {\n                id: \"conditii\",\n                heading: \"2. Condiții de eligibilitate\",\n                content: [\n                    \"Pentru a obține un credit personal \\xeen 2026, vei avea nevoie de: v\\xe2rsta \\xeentre 18 și 70 de ani la finalul creditului, venituri stabile și demonstrabile, un istoricul de credit acceptabil și documente de identitate valabile.\",\n                    \"Chiar dacă ai \\xeenregistrări negative la Biroul de Credit, unele bănci partenere acceptă dosare cu istorii dificile. Un broker autorizat te poate ajuta să identifici exact ce opțiuni ai disponibile.\",\n                    \"Venitul minim acceptat variază \\xeen funcție de suma solicitată și de bancă. De regulă, rata lunară nu trebuie să depășească 40-45% din venitul net al familiei.\"\n                ]\n            },\n            {\n                id: \"documente\",\n                heading: \"3. Documente necesare\",\n                content: [\n                    \"Lista de documente diferă ușor de la o bancă la alta, dar \\xeen general vei avea nevoie de: carte de identitate \\xeen termen de valabilitate, adeverință de venit sau fluturași de salariu (ultimele 3 luni), extras de cont (ultimele 3-6 luni) și, opțional, un contract de muncă.\",\n                    \"Dacă ești PFA sau desfășori activitate independentă, vei mai avea nevoie de declarația de venit și certificatul de \\xeenregistrare. Banca poate solicita documente suplimentare \\xeen funcție de profilul tău.\"\n                ]\n            },\n            {\n                id: \"cum-compari\",\n                heading: \"4. Cum compari ofertele corect\",\n                content: [\n                    \"Nu te uita doar la rata dob\\xe2nzii nominale — compară \\xeentotdeauna DAE (Dob\\xe2nda Anuală Efectivă), care include toate costurile creditului: dob\\xe2nda, comisioanele și asigurările obligatorii.\",\n                    \"Folosește un calculator de credit pentru a vedea rata lunară exactă și costul total al \\xeemprumutului. O diferență de 1-2% la DAE poate \\xeensemna mii de lei \\xeen plus pe toată durata creditului.\",\n                    \"Un broker de credite autorizat compară automat ofertele celor mai mari bănci și \\xeeți prezintă cele mai avantajoase variante pentru profilul tău — fără niciun cost pentru tine.\"\n                ]\n            },\n            {\n                id: \"procesul\",\n                heading: \"5. Procesul de aplicare pas cu pas\",\n                content: [\n                    \"Pasul 1 — Consultație inițială: Discuți cu un specialist suma necesară, durata dorită și situația ta financiară. La CS Credit Advisor, această consultație este 100% gratuită.\",\n                    \"Pasul 2 — Analiza dosarului: Specialistul identifică cel mai potrivit produs și bancă pentru profilul tău și pregătește dosarul de aplicare.\",\n                    \"Pasul 3 — Aplicarea la bancă: Dosarul tău este depus la bancă cu sprijinul consultantului. Vei fi informat la fiecare etapă.\",\n                    \"Pasul 4 — Aprobare și semnare: Odată aprobat, semnezi contractul la bancă. Banii ajung \\xeen contul tău \\xeen 1-3 zile lucrătoare.\"\n                ]\n            },\n            {\n                id: \"sfaturi\",\n                heading: \"6. Sfaturi pentru a obține cea mai bună ofertă\",\n                content: [\n                    \"Verifică-ți istoricul de credit \\xeenainte de aplicare — poți solicita un raport gratuit la Biroul de Credit. Corectează eventualele erori \\xeenainte de a depune dosarul.\",\n                    \"Nu aplica la mai multe bănci simultan — fiecare interogare la Biroul de Credit \\xeeți poate afecta scorul. Lucrează cu un broker care face o singură interogare și negociază \\xeen numele tău.\",\n                    \"Negociază \\xeentotdeauna — băncile au marjă de negociere, mai ales pentru clienții cu profil bun. Un broker experimentat poate obține condiții mai avantajoase dec\\xe2t ai obține singur.\"\n                ]\n            }\n        ],\n        conclusion: \"Obținerea unui credit personal \\xeen 2026 nu trebuie să fie un proces complicat. Cu documentele corecte, o comparație atentă a ofertelor și sprijinul unui broker autorizat, poți accesa finanțarea de care ai nevoie \\xeen condiții avantajoase. Consultanții CS Credit Advisor sunt disponibili să te ghideze gratuit prin fiecare pas al procesului.\"\n    },\n    {\n        slug: \"prima-casa-noua-casa-ghid-comparativ\",\n        title: \"Prima Casă sau Noua Casă: Cum Alegi Cel Mai Bun Program\",\n        excerpt: \"Comparăm programele Prima Casă și Noua Casă — avans, dob\\xe2nzi, condiții de eligibilitate și ce s-a schimbat \\xeen 2026.\",\n        date: \"20 Februarie 2026\",\n        readTime: \"6 min\",\n        category: \"Ghiduri\",\n        sections: [\n            {\n                id: \"diferente\",\n                heading: \"1. Principalele diferențe\",\n                content: [\n                    \"Programul Noua Casă a \\xeenlocuit Prima Casă și vine cu c\\xe2teva modificări importante: plafonul maxim al imobilului a crescut, iar condițiile de eligibilitate sunt ușor modificate.\",\n                    \"Ambele programe sunt garantate parțial de stat și permit achiziționarea primei proprietăți cu un avans minim, mult mai mic dec\\xe2t pentru un credit ipotecar clasic.\"\n                ]\n            },\n            {\n                id: \"avans\",\n                heading: \"2. Avansul minim\",\n                content: [\n                    \"Pentru Noua Casă, avansul minim este de 15% din valoarea proprietății, față de 5% c\\xe2t era \\xeen Prima Casă. Această modificare urmărește reducerea riscului de supra\\xeendatorare.\",\n                    \"Pentru un credit ipotecar clasic, băncile cer de regulă un avans de 20-25%. Prin urmare, programul Noua Casă răm\\xe2ne avantajos pentru cei care nu au economii mari.\"\n                ]\n            },\n            {\n                id: \"eligibilitate\",\n                heading: \"3. Condiții de eligibilitate\",\n                content: [\n                    \"Poți accesa programul Noua Casă dacă nu deții \\xeen prezent nicio proprietate imobiliară sau ai o cotă de cel mult 50% dintr-una. Venitul familiei trebuie să fie suficient pentru a susține rata lunară.\",\n                    \"Nu există restricții legate de istoricul de credit \\xeen sensul strict, dar băncile participante pot refuza dosarele cu \\xeenregistrări negative semnificative.\"\n                ]\n            }\n        ],\n        conclusion: \"Dacă \\xeendeplinești condițiile, Noua Casă poate fi o soluție avantajoasă pentru achiziționarea primei locuințe. Consultanții CS Credit Advisor te ajută gratuit să determini eligibilitatea și să pregătești dosarul.\"\n    },\n    {\n        slug: \"biroul-de-credit-explicat\",\n        title: \"Ce Este Biroul de Credit și Cum \\xceți Afectează Dosarul\",\n        excerpt: \"Cum funcționează Biroul de Credit \\xeen Rom\\xe2nia, ce \\xeenseamnă un scor bun sau slab și ce poți face dacă ai \\xeenregistrări negative.\",\n        date: \"10 Februarie 2026\",\n        readTime: \"5 min\",\n        category: \"Sfaturi\",\n        sections: [\n            {\n                id: \"ce-este\",\n                heading: \"1. Ce este Biroul de Credit\",\n                content: [\n                    \"Biroul de Credit (BC) este o bază de date națională care centralizează informații despre comportamentul de plată al persoanelor fizice și juridice. Toate băncile și instituțiile financiare \\xeenregistrate raportează lunar datele clienților.\",\n                    \"Informațiile includ creditele active, istoricul plăților, eventualele restanțe sau executări silite. Aceste date sunt folosite de bănci pentru a evalua riscul unui nou dosar de credit.\"\n                ]\n            },\n            {\n                id: \"scor\",\n                heading: \"2. Cum se calculează scorul de credit\",\n                content: [\n                    \"Scorul de credit variază de la 300 la 850 de puncte. Un scor peste 700 este considerat bun, peste 750 — excelent. Sub 600 poate \\xeengreuna accesul la credite \\xeen condiții standard.\",\n                    \"Factorii care influențează scorul: plățile la timp (cel mai important), gradul de utilizare a creditelor existente, diversitatea produselor financiare și vechimea istoricului de credit.\"\n                ]\n            },\n            {\n                id: \"negative\",\n                heading: \"3. Ce se \\xeent\\xe2mplă cu \\xeenregistrările negative\",\n                content: [\n                    \"\\xcenregistrările negative răm\\xe2n \\xeen baza de date timp de 4 ani de la data \\xeenregistrării sau 7 ani pentru restanțe severe. Dacă ai achitat datoria, statutul se actualizează dar \\xeenregistrarea răm\\xe2ne vizibilă.\",\n                    \"Chiar și cu \\xeenregistrări negative, există soluții de creditare. Unele bănci și IFN-uri acceptă dosare cu risc mai ridicat, la dob\\xe2nzi mai mari. Un broker te poate ajuta să identifici opțiunile disponibile.\"\n                ]\n            }\n        ],\n        conclusion: \"\\xcențelegerea Biroului de Credit te ajută să iei decizii financiare mai bune. Dacă ai nelămuriri despre istoricul tău sau vrei să știi ce opțiuni de creditare ai, consultanții CS Credit Advisor \\xeeți oferă gratuit această informație.\"\n    },\n    {\n        slug: \"refinantare-credit-ghid\",\n        title: \"Refinanțare Credit: C\\xe2nd Merită și Cum Procedezi\",\n        excerpt: \"Refinanțarea poate reduce rata lunară sau costul total al creditului. Află c\\xe2nd are sens să refinanțezi și care sunt pașii necesari.\",\n        date: \"28 Ianuarie 2026\",\n        readTime: \"5 min\",\n        category: \"Sfaturi\",\n        sections: [\n            {\n                id: \"ce-este\",\n                heading: \"1. Ce \\xeenseamnă refinanțarea\",\n                content: [\n                    \"Refinanțarea \\xeenseamnă contractarea unui nou credit pentru a plăti creditul sau creditele existente, de obicei la condiții mai avantajoase: dob\\xe2ndă mai mică, rată lunară redusă sau perioadă de rambursare ajustată.\",\n                    \"Poate fi făcută la aceeași bancă (renegociere) sau la o altă bancă. \\xcen al doilea caz, noul creditor plătește soldul rămas al creditului vechi.\"\n                ]\n            },\n            {\n                id: \"cand-merita\",\n                heading: \"2. C\\xe2nd merită să refinanțezi\",\n                content: [\n                    \"Refinanțarea are sens c\\xe2nd: dob\\xe2nzile au scăzut semnificativ față de momentul contractării, ai \\xeembunătățit scorul de credit și poți accesa condiții mai bune, sau vrei să consolidezi mai multe credite \\xeentr-unul singur.\",\n                    \"Nu uita să iei \\xeen calcul costurile refinanțării: comisionul de rambursare anticipată (dacă există), costurile noului credit și eventualele taxe notariale pentru ipotecare.\"\n                ]\n            }\n        ],\n        conclusion: \"Refinanțarea poate fi o decizie financiară excelentă, dar necesită o analiză atentă a costurilor și beneficiilor. Consultanții CS Credit Advisor calculează gratuit dacă refinanțarea este avantajoasă pentru situația ta.\"\n    },\n    {\n        slug: \"credit-cu-istorii-negative\",\n        title: \"Credit cu Istoric Negativ la Biroul de Credit: Există Soluții?\",\n        excerpt: \"Ai restanțe sau \\xeenregistrări negative? Află ce opțiuni de creditare ai \\xeen 2026 și cum poți crește șansele de aprobare.\",\n        date: \"15 Ianuarie 2026\",\n        readTime: \"6 min\",\n        category: \"Sfaturi\",\n        sections: [\n            {\n                id: \"situatia\",\n                heading: \"1. Ce \\xeenseamnă istoric negativ\",\n                content: [\n                    \"Istoricul negativ include: plăți \\xeent\\xe2rziate cu mai mult de 30 de zile, credite trecute la pierderi, executări silite sau declararea insolvenței. Fiecare tip de \\xeenregistrare are un impact diferit asupra scorului.\",\n                    \"Important de știut: dacă ai achitat integral datoria, banca are obligația să actualizeze statutul la Biroul de Credit. Verifică periodic raportul pentru a te asigura că datele sunt corecte.\"\n                ]\n            },\n            {\n                id: \"optiuni\",\n                heading: \"2. Opțiuni de creditare disponibile\",\n                content: [\n                    \"Nu toate băncile aplică aceleași criterii. Unele bănci partenere CS Credit Advisor acceptă dosare cu \\xeenregistrări negative vechi (3-4 ani) dacă situația curentă este stabilă.\",\n                    \"IFN-urile (instituții financiare nebancare) sunt o alternativă, dar cu dob\\xe2nzi semnificativ mai mari. Le recomandăm doar ca soluție temporară, nu pe termen lung.\",\n                    \"Creditele cu garanție (ipotecare) au o rată de aprobare mai mare chiar și cu istoricul negativ, deoarece riscul băncii este acoperit de proprietate.\"\n                ]\n            }\n        ],\n        conclusion: \"Un istoric negativ nu \\xeenseamnă că nu mai poți accesa creditare. Specialiștii CS Credit Advisor au experiență \\xeen dosare complexe și știu exact ce bănci acceptă situații similare cu a ta. Consultația este gratuită.\"\n    },\n    {\n        slug: \"top-banci-romania-2026\",\n        title: \"Top Bănci Rom\\xe2nia 2026: Comparație Dob\\xe2nzi Credite Personale\",\n        excerpt: \"Comparăm ofertele principale ale băncilor din Rom\\xe2nia pentru credite personale \\xeen 2026: BCR, BRD, Banca Transilvania, ING și Raiffeisen.\",\n        date: \"3 Ianuarie 2026\",\n        readTime: \"7 min\",\n        category: \"Știri\",\n        sections: [\n            {\n                id: \"context\",\n                heading: \"1. Contextul pieței \\xeen 2026\",\n                content: [\n                    \"După perioada de creșteri succesive ale dob\\xe2nzilor din 2022-2024, piața creditelor din Rom\\xe2nia a intrat \\xeentr-o fază de stabilizare. DAE pentru creditele personale se situează \\xeen prezent \\xeentre 7% și 16%, \\xeen funcție de bancă și profilul clientului.\",\n                    \"Concurența \\xeentre băncile mari a dus la \\xeembunătățirea condițiilor pentru clienții cu profil bun: comisioane reduse, procese digitalizate și aprobare mai rapidă.\"\n                ]\n            },\n            {\n                id: \"comparatie\",\n                heading: \"2. Comparație orientativă\",\n                content: [\n                    \"BCR — una dintre cele mai mari bănci din Rom\\xe2nia, oferă credite personale cu DAE \\xeentre 8% și 14%. Procesul de aprobare este rapid pentru clienții existenți.\",\n                    \"BRD — dob\\xe2nzi competitive, cu produse special dedicate salariaților și pensionarilor. DAE orientativă: 8.5% - 15%.\",\n                    \"Banca Transilvania — flexibilă \\xeen evaluarea dosarelor și cu una dintre cele mai bune experiențe digitale. DAE: 7.5% - 13%.\",\n                    \"ING — 100% online, procese rapide, dar cu criterii mai stricte de eligibilitate. DAE: 8% - 12%.\",\n                    \"Raiffeisen — oferte personalizate, comisioane mici, DAE orientativă: 8% - 14%.\"\n                ]\n            },\n            {\n                id: \"cum-alegi\",\n                heading: \"3. Cum alegi banca potrivită\",\n                content: [\n                    \"Cel mai important factor nu este dob\\xe2nda nominală ci DAE — dob\\xe2nda anuală efectivă care include toate costurile. Două credite cu aceeași rată nominală pot avea costuri totale foarte diferite.\",\n                    \"Un broker de credite autorizat compară automat toate ofertele disponibile și negociază \\xeen numele tău, fără costuri suplimentare. Astfel, ai garanția că alegi cea mai bună ofertă pentru situația ta specifică.\"\n                ]\n            }\n        ],\n        conclusion: \"Fiecare bancă are avantajele și dezavantajele ei. Cel mai eficient mod de a alege este prin intermediul unui broker autorizat care cunoaște \\xeen detaliu ofertele curente și poate negocia condiții personalizate. CS Credit Advisor colaborează cu toate cele 5 bănci enumerate și oferă consultanță gratuită.\"\n    }\n];\nfunction getArticle(slug) {\n    return articles.find((a)=>a.slug === slug);\n}\nfunction getFeaturedArticle() {\n    return articles.find((a)=>a.featured) ?? articles[0];\n}\nfunction getRecentArticles(count = 6, excludeSlug) {\n    return articles.filter((a)=>a.slug !== excludeSlug).slice(0, count);\n}\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(rsc)/./lib/articles.ts\n");

